64,0.00013719653,0.009010691,-0.03207063,-0.0060566724,0.0008608494,-0.011793036,0.0022980077,0.004285967,0.011904985,0.029378004,0.0049330597]', 'Dominadas', 'El mejor ejercicio de peso corporal para espalda. Cuelga y sube hasta pasar la barbilla.', '["Hang from a bar with an overhand grip, hands shoulder-width apart.", "Engage your lats and pull your body up until your chin clears the bar.", "Pause briefly at the top, squeezing your shoulder blades together.", "Slowly lower yourself back to the starting position with control."]', '["Cuélgate de una barra con agarre prono, manos al ancho de hombros.", "Activa tus dorsales y sube tu cuerpo hasta que tu barbilla pase la barra.", "Haz una breve pausa arriba, juntando tus omóplatos.", "Baja lentamente a la posición inicial con control."]', '[{"avoid": "Perform strict pull-ups, focusing on muscle contraction.", "title": "Using Momentum (Kipping)", "avoid_es": "Realiza dominadas estrictas, enfocándote en la contracción muscular.", "title_es": "Usar Impulso (Kipping)", "description": "Kipping reduces lat activation and places stress on shoulders and elbows.", "description_es": "El kipping reduce la activación de los dorsales y estresa hombros y codos."}, {"avoid": "Ensure full extension at the bottom and chin over the bar at the top.", "title": "Incomplete Range of Motion", "avoid_es": "Asegura extensión completa abajo y barbilla sobre la barra arriba.", "title_es": "Rango de Movimiento Incompleto", "description": "Not fully extending or pulling up limits muscle development.", "description_es": "No extender o subir completamente limita el desarrollo muscular."}]', '[{"avoid": "Perform strict pull-ups, focusing on muscle contraction.", "title": "Using Momentum (Kipping)", "avoid_es": "Realiza dominadas estrictas, enfocándote en la contracción muscular.", "title_es": "Usar Impulso (Kipping)", "description": "Kipping reduces lat activation and places stress on shoulders and elbows.", "description_es": "El kipping reduce la activación de los dorsales y estresa hombros y codos."}, {"avoid": "Ensure full extension at the bottom and chin over the bar at the top.", "title": "Incomplete Range of Motion", "avoid_es": "Asegura extensión completa abajo y barbilla sobre la barra arriba.", "title_es": "Rango de Movimiento Incompleto", "description": "Not fully extending or pulling up limits muscle development.", "description_es": "No extender o subir completamente limita el desarrollo muscular."}]', '["Scapular Retraction: Initiate pull by depressing shoulder blades.", "Core Engagement: Keep core tight to prevent swinging.", "Controlled Descent: Lower slowly to maximize time under tension."]', '["Retracción Escapular: Inicia jalón deprimiendo omóplatos.", "Activación del Core: Mantén el core apretado para evitar balanceo.", "Descenso Controlado: Baja lentamente para maximizar tiempo bajo tensión."]', 'https://www.youtube.com/results?search_query=Pull%20Up%20(Dominadas)%20proper%20form%20tutorial'),
