', '[{"avoid": "Maintain a neutral spine throughout the movement. Engage core muscles.", "title": "Hyperextension of the Lower Back", "avoid_es": "Mantén una columna vertebral neutra durante todo el movimiento. Contrae los músculos del core.", "title_es": "Hiperextensión de la Zona Lumbar", "description": "Arching the lower back excessively can strain the lumbar spine, leading to pain or injury.", "description_es": "Arquear la zona lumbar excesivamente puede tensar la columna lumbar, causando dolor o lesión."}, {"avoid": "Perform the movement slowly and controlled, focusing on muscle contraction.", "title": "Using Momentum", "avoid_es": "Realiza el movimiento de forma lenta y controlada, centrándote en la contracción muscular.", "title_es": "Usar Impulso", "description": "Relying on momentum reduces hamstring and glute activation, making the exercise less effective.", "description_es": "Depender del impulso reduce la activación de isquiotibiales y glúteos, haciendo el ejercicio menos efectivo."}]', '["Tempo Control: Emphasize a slow eccentric (lowering) phase for greater muscle tension.", "Full Range of Motion: Ensure you go through the full range for optimal muscle engagement.", "Core Engagement: Keep your core tight to stabilize your torso and protect your back."]', '["Control del Tempo: Enfatiza una fase excéntrica lenta (bajada) para mayor tensión muscular.", "Rango Completo de Movimiento: Asegúrate de usar el rango completo para una activación óptima.", "Activación del Core: Mantén el core apretado para estabilizar el torso y proteger la espalda."]', 'https://www.youtube.com/results?search_query=Glute-Ham%20Raise%20proper%20form%20tutorial'),
